1	import {
2	  Injectable,
3	  NotFoundException,
4	  Logger,
5	  ForbiddenException,
6	} from '@nestjs/common';
7	import { InjectRepository } from '@nestjs/typeorm';
8	import { Repository, LessThanOrEqual } from 'typeorm';
9	import { ConfigService } from '@nestjs/config';
10	import { Cron, CronExpression } from '@nestjs/schedule';
11	import { InventoryLot } from './entities/inventory-lot.entity';
12	import { InventoryAdjustment } from './entities/inventory-adjustment.entity';
13	import { CreateLotDto } from './dto/create-lot.dto';
14	import { AdjustStockDto } from './dto/adjust-stock.dto';
15	import { NotificationsService } from '../notifications/notifications.service';
16	import { Sku } from '../products/entities/sku.entity';
17	
18	@Injectable()
19	export class InventoryService {
20	  private readonly logger = new Logger(InventoryService.name);
21	
22	  constructor(
23	    @InjectRepository(InventoryLot)
24	    private readonly lotRepo: Repository<InventoryLot>,
25	    @InjectRepository(InventoryAdjustment)
26	    private readonly adjustmentRepo: Repository<InventoryAdjustment>,
27	    @InjectRepository(Sku)
28	    private readonly skuRepo: Repository<Sku>,
29	    private readonly configService: ConfigService,
30	    private readonly notificationsService: NotificationsService,
31	  ) {}
32	
33	  private getUserStoreId(user: any): string | null {
34	    return user?.storeId ?? user?.store_id ?? null;
35	  }
36	
37	  private resolveStoreScope(user: any): string | null {
38	    if (user?.role === 'store_admin') {
39	      const storeId = this.getUserStoreId(user);
40	      if (!storeId) {
41	        throw new ForbiddenException('Store admin has no assigned store');
42	      }
43	      return storeId;
44	    }
45	    return null;
46	  }
47	
48	  /* ── Lots ── */
49	
50	  async createLot(dto: CreateLotDto, user: any): Promise<InventoryLot> {
51	    const storeId = this.resolveStoreScope(user);
52	    if (storeId) {
53	      const scopedSku = await this.skuRepo
54	        .createQueryBuilder('sku')
55	        .innerJoin('sku.product', 'product')
56	        .where('sku.id = :skuId', { skuId: dto.skuId })
57	        .andWhere('product.store_id = :storeId', { storeId })
58	        .getOne();
59	      if (!scopedSku) {
60	        throw new NotFoundException(`SKU ${dto.skuId} not found`);
61	      }
62	    }
63	
64	    const lot = this.lotRepo.create({
65	      sku_id: dto.skuId,
66	      batch_code: dto.batchCode,
67	      expiration_date: dto.expirationDate ?? null,
68	      quantity: dto.quantity,
69	    });
70	    return this.lotRepo.save(lot);
71	  }
72	
73	  async findAllLots(user: any, skuId?: string): Promise<InventoryLot[]> {
74	    const storeId = this.resolveStoreScope(user);
75	    const qb = this.lotRepo
76	      .createQueryBuilder('lot')
77	      .leftJoinAndSelect('lot.sku', 'sku')
78	      .leftJoin('sku.product', 'product');
79	
80	    if (skuId) qb.andWhere('lot.sku_id = :skuId', { skuId });
81	    if (storeId) qb.andWhere('product.store_id = :storeId', { storeId });
82	
83	    return qb.getMany();
84	  }
85	
86	  async findLotById(id: string, user?: any): Promise<InventoryLot> {
87	    const storeId = this.resolveStoreScope(user);
88	    const qb = this.lotRepo
89	      .createQueryBuilder('lot')
90	      .leftJoinAndSelect('lot.sku', 'sku')
91	      .leftJoin('sku.product', 'product')
92	      .where('lot.id = :id', { id });
93	
94	    if (storeId) qb.andWhere('product.store_id = :storeId', { storeId });
95	
96	    const lot = await qb.getOne();
97	    if (!lot) throw new NotFoundException(`Lot ${id} not found`);
98	    return lot;
99	  }
100	
101	  async updateLot(
102	    id: string,
103	    updates: Partial<Pick<InventoryLot, 'batch_code' | 'expiration_date' | 'quantity'>>,
104	    user: any,
105	  ): Promise<InventoryLot> {
106	    const lot = await this.findLotById(id, user);
107	    Object.assign(lot, updates);
108	    return this.lotRepo.save(lot);
109	  }
110	
111	  /* ── Stock Adjustment ── */
112	
113	  async adjustStock(
114	    dto: AdjustStockDto,
115	    userId: string,
116	    user: any,
117	  ): Promise<{ adjustment: InventoryAdjustment; alreadyExisted: boolean }> {
118	    this.resolveStoreScope(user);
119	
120	    const existing = await this.adjustmentRepo.findOne({
121	      where: { idempotency_key: dto.idempotencyKey },
122	    });
123	    if (existing) {
124	      await this.findLotById(existing.lot_id, user);
125	      return { adjustment: existing, alreadyExisted: true };
126	    }
127	
128	    const lot = await this.findLotById(dto.lotId, user);
129	    lot.quantity += dto.delta;
130	    await this.lotRepo.save(lot);
131	
132	    const adjustment = this.adjustmentRepo.create({
133	      lot_id: dto.lotId,
134	      delta: dto.delta,
135	      reason_code: dto.reasonCode,
136	      idempotency_key: dto.idempotencyKey,
137	      adjusted_by: userId,
138	    });
139	    const saved = await this.adjustmentRepo.save(adjustment);
140	
141	    // Check low stock threshold — persist notification
142	    const threshold = this.configService.get<number>('lowStockThreshold', 10);
143	    if (lot.quantity < threshold && lot.quantity >= 0) {
144	      this.logger.warn(
145	        `Low stock: Lot ${lot.id} (SKU ${lot.sku_id}) has ${lot.quantity} units (threshold: ${threshold})`,
146	      );
147	      await this.notificationsService.createForAdmins(
148	        'low_stock',
149	        `Low stock alert: Lot ${lot.id} (SKU ${lot.sku_id}) has ${lot.quantity} units, below threshold of ${threshold}.`,
150	      );
151	    }
152	
153	    return { adjustment: saved, alreadyExisted: false };
154	  }
155	
156	  /* ── Cron Jobs ── */
157	
158	  @Cron(CronExpression.EVERY_DAY_AT_MIDNIGHT)
159	  async checkExpiringLots(): Promise<void> {
160	    const sevenDaysFromNow = new Date();
161	    sevenDaysFromNow.setDate(sevenDaysFromNow.getDate() + 7);
162	    const dateStr = sevenDaysFromNow.toISOString().split('T')[0];
163	
164	    const expiringLots = await this.lotRepo.find({
165	      where: { expiration_date: LessThanOrEqual(dateStr) },
166	      relations: ['sku'],
167	    });
168	
169	    for (const lot of expiringLots) {
170	      if (lot.quantity > 0) {
171	        this.logger.warn(
172	          `Expiring lot: ${lot.id} (batch ${lot.batch_code}) expires ${lot.expiration_date} with ${lot.quantity} units`,
173	        );
174	        await this.notificationsService.createForAdmins(
175	          'expiring_inventory',
176	          `Lot ${lot.id} (batch ${lot.batch_code}) expires on ${lot.expiration_date} with ${lot.quantity} units remaining.`,
177	        );
178	      }
179	    }
180	  }
181	
182	  @Cron(CronExpression.EVERY_10_MINUTES)
183	  async checkLowStock(): Promise<void> {
184	    const threshold = this.configService.get<number>('lowStockThreshold', 10);
185	    const lots = await this.lotRepo
186	      .createQueryBuilder('lot')
187	      .where('lot.quantity < :threshold', { threshold })
188	      .andWhere('lot.quantity > 0')
189	      .getMany();
190	
191	    for (const lot of lots) {
192	      this.logger.warn(
193	        `Low stock: Lot ${lot.id} (SKU ${lot.sku_id}) has ${lot.quantity} units`,
194	      );
195	      await this.notificationsService.createForAdmins(
196	        'low_stock',
197	        `Low stock: Lot ${lot.id} (SKU ${lot.sku_id}) has ${lot.quantity} units (threshold: ${threshold}).`,
198	      );
199	    }
200	  }
201	}
202	
