1	import {
2	  Controller,
3	  Get,
4	  Post,
5	  Patch,
6	  Param,
7	  Body,
8	  Query,
9	  ParseUUIDPipe,
10	  UseGuards,
11	  HttpCode,
12	  HttpStatus,
13	  Res,
14	} from '@nestjs/common';
15	import { Response } from 'express';
16	import {
17	  ApiTags,
18	  ApiBearerAuth,
19	  ApiOperation,
20	  ApiParam,
21	  ApiQuery,
22	  ApiResponse,
23	} from '@nestjs/swagger';
24	import { InventoryService } from './inventory.service';
25	import { CreateLotDto } from './dto/create-lot.dto';
26	import { AdjustStockDto } from './dto/adjust-stock.dto';
27	import { Roles } from '../common/decorators/roles.decorator';
28	import { RolesGuard } from '../common/guards/roles.guard';
29	import { CurrentUser } from '../common/decorators/current-user.decorator';
30	import { TraceId } from '../common/decorators/trace-id.decorator';
31	import { AuditService } from '../audit/audit.service';
32	
33	@ApiTags('Inventory')
34	@ApiBearerAuth()
35	@Controller('inventory')
36	@UseGuards(RolesGuard)
37	export class InventoryController {
38	  constructor(
39	    private readonly inventoryService: InventoryService,
40	    private readonly auditService: AuditService,
41	  ) {}
42	
43	  @Post('lots')
44	  @Roles('store_admin', 'platform_admin')
45	  @ApiOperation({ summary: 'Create an inventory lot' })
46	  @ApiResponse({ status: 201, description: 'Lot created' })
47	  async createLot(
48	    @Body() dto: CreateLotDto,
49	    @CurrentUser() user: any,
50	    @TraceId() traceId?: string,
51	  ) {
52	    const lot = await this.inventoryService.createLot(dto, user);
53	    await this.auditService.log(
54	      user.id,
55	      'create_inventory_lot',
56	      'inventory_lot',
57	      lot.id,
58	      { skuId: dto.skuId },
59	      traceId,
60	    );
61	    return lot;
62	  }
63	
64	  @Get('lots')
65	  @Roles('store_admin', 'platform_admin')
66	  @ApiOperation({ summary: 'List inventory lots' })
67	  @ApiQuery({ name: 'skuId', required: false, type: 'string' })
68	  @ApiResponse({ status: 200, description: 'List of lots' })
69	  findAllLots(@CurrentUser() user: any, @Query('skuId') skuId?: string) {
70	    return this.inventoryService.findAllLots(user, skuId);
71	  }
72	
73	  @Patch('lots/:id')
74	  @Roles('store_admin', 'platform_admin')
75	  @ApiOperation({ summary: 'Update an inventory lot' })
76	  @ApiParam({ name: 'id', type: 'string', format: 'uuid' })
77	  @ApiResponse({ status: 200, description: 'Lot updated' })
78	  updateLot(
79	    @Param('id', ParseUUIDPipe) id: string,
80	    @Body() dto: Partial<CreateLotDto>,
81	    @CurrentUser() user: any,
82	    @TraceId() traceId?: string,
83	  ) {
84	    const updates: any = {};
85	    if (dto.batchCode !== undefined) updates.batch_code = dto.batchCode;
86	    if (dto.expirationDate !== undefined)
87	      updates.expiration_date = dto.expirationDate;
88	    if (dto.quantity !== undefined) updates.quantity = dto.quantity;
89	    return this.inventoryService.updateLot(id, updates, user).then(async (lot) => {
90	      await this.auditService.log(
91	        user.id,
92	        'update_inventory_lot',
93	        'inventory_lot',
94	        id,
95	        { fields: Object.keys(dto || {}) },
96	        traceId,
97	      );
98	      return lot;
99	    });
100	  }
101	
102	  @Post('adjust')
103	  @Roles('store_admin', 'platform_admin')
104	  @HttpCode(HttpStatus.OK)
105	  @ApiOperation({ summary: 'Adjust stock with idempotency' })
106	  @ApiResponse({ status: 200, description: 'Stock adjusted' })
107	  @ApiResponse({ status: 201, description: 'New adjustment created' })
108	  async adjustStock(
109	    @Body() dto: AdjustStockDto,
110	    @CurrentUser('id') userId: string,
111	    @CurrentUser() user: any,
112	    @Res({ passthrough: true }) res: Response,
113	    @TraceId() traceId?: string,
114	  ) {
115	    const { adjustment, alreadyExisted } =
116	      await this.inventoryService.adjustStock(dto, userId, user);
117	    if (!alreadyExisted) {
118	      res.status(HttpStatus.CREATED);
119	    }
120	    await this.auditService.log(
121	      user.id,
122	      'adjust_inventory_stock',
123	      'inventory_lot',
124	      dto.lotId,
125	      {
126	        delta: dto.delta,
127	        reasonCode: dto.reasonCode,
128	        idempotencyKey: dto.idempotencyKey,
129	        alreadyExisted,
130	      },
131	      traceId,
132	    );
133	    return adjustment;
134	  }
135	}
