1	/**
2	 * ProctorWorks Inventory API Integration Tests
3	 *
4	 * These tests run against a real NestJS application backed by PostgreSQL.
5	 * Requires DATABASE_URL (or defaults to local dev DB).
6	 */
7	
8	process.env.DATABASE_URL =
9	  process.env.DATABASE_URL ||
10	  'postgres://proctorworks:proctorworks@127.0.0.1:5433/proctorworks';
11	
12	import { Test, TestingModule } from '@nestjs/testing';
13	import { INestApplication, ValidationPipe } from '@nestjs/common';
14	const request = require('supertest');
15	import { AppModule } from '../src/app.module';
16	
17	// ---------------------------------------------------------------------------
18	// Helpers
19	// ---------------------------------------------------------------------------
20	
21	const UNIQUE = Date.now();
22	
23	function logStep(method: string, path: string, status?: number): void {
24	  if (status !== undefined) {
25	    console.log(`  \u2190 ${status}`);
26	  } else {
27	    console.log(`  \u2192 ${method} ${path}`);
28	  }
29	}
30	
31	async function login(
32	  server: any,
33	  username: string,
34	  password: string,
35	): Promise<string> {
36	  logStep('POST', '/auth/login');
37	  const res = await request(server)
38	    .post('/auth/login')
39	    .send({ username, password });
40	  logStep('POST', '/auth/login', res.status);
41	  return res.body.accessToken;
42	}
43	
44	// ---------------------------------------------------------------------------
45	// Suite
46	// ---------------------------------------------------------------------------
47	
48	describe('Inventory API', () => {
49	  let app: INestApplication;
50	  let server: any;
51	  let adminToken: string;
52	
53	  // Shared IDs created in beforeAll
54	  let categoryId: string;
55	  let brandId: string;
56	  let productId: string;
57	  let skuId: string;
58	  let lotId: string;
59	
60	  beforeAll(async () => {
61	    const moduleFixture: TestingModule = await Test.createTestingModule({
62	      imports: [AppModule],
63	    }).compile();
64	
65	    app = moduleFixture.createNestApplication();
66	    app.useGlobalPipes(
67	      new ValidationPipe({ whitelist: true, transform: true }),
68	    );
69	    await app.init();
70	    server = app.getHttpServer();
71	
72	    // Login as admin
73	    adminToken = await login(server, 'admin', 'Admin1234!');
74	    expect(adminToken).toBeDefined();
75	
76	    // Create a category
77	    logStep('POST', '/categories');
78	    const catRes = await request(server)
79	      .post('/categories')
80	      .set('Authorization', `Bearer ${adminToken}`)
81	      .send({ name: `InvTestCategory-${UNIQUE}` });
82	    logStep('POST', '/categories', catRes.status);
83	    expect(catRes.status).toBe(201);
84	    categoryId = catRes.body.id;
85	
86	    // Create a brand
87	    logStep('POST', '/brands');
88	    const brandRes = await request(server)
89	      .post('/brands')
90	      .set('Authorization', `Bearer ${adminToken}`)
91	      .send({ name: `InvTestBrand-${UNIQUE}` });
92	    logStep('POST', '/brands', brandRes.status);
93	    expect(brandRes.status).toBe(201);
94	    brandId = brandRes.body.id;
95	
96	    // Create a product
97	    logStep('POST', '/products');
98	    const prodRes = await request(server)
99	      .post('/products')
100	      .set('Authorization', `Bearer ${adminToken}`)
101	      .send({
102	        name: `InvTestProduct-${UNIQUE}`,
103	        categoryId,
104	        brandId,
105	      });
106	    logStep('POST', '/products', prodRes.status);
107	    expect(prodRes.status).toBe(201);
108	    productId = prodRes.body.id;
109	
110	    // Create a SKU
111	    logStep('POST', `/products/${productId}/skus`);
112	    const skuRes = await request(server)
113	      .post(`/products/${productId}/skus`)
114	      .set('Authorization', `Bearer ${adminToken}`)
115	      .send({
116	        skuCode: `INV-SKU-${UNIQUE}`,
117	        priceCents: 1500,
118	      });
119	    logStep('POST', `/products/${productId}/skus`, skuRes.status);
120	    expect(skuRes.status).toBe(201);
121	    skuId = skuRes.body.id;
122	  }, 30_000);
123	
124	  afterAll(async () => {
125	    if (app) await app.close();
126	  });
127	
128	  // -------------------------------------------------------------------------
129	  // 1. POST /inventory/lots -> 201, creates lot
130	  // -------------------------------------------------------------------------
131	  describe('POST /inventory/lots', () => {
132	    it('should create a lot with batchCode, quantity, and expirationDate', async () => {
133	      logStep('POST', '/inventory/lots');
134	      const res = await request(server)
135	        .post('/inventory/lots')
136	        .set('Authorization', `Bearer ${adminToken}`)
137	        .send({
138	          skuId,
139	          batchCode: `BATCH-${UNIQUE}`,
140	          quantity: 50,
141	          expirationDate: '2027-06-30',
142	        });
143	      logStep('POST', '/inventory/lots', res.status);
144	
145	      expect(res.status).toBe(201);
146	      expect(res.body).toHaveProperty('id');
147	      expect(res.body.batch_code).toBe(`BATCH-${UNIQUE}`);
148	      expect(res.body.quantity).toBe(50);
149	      expect(res.body.expiration_date).toBe('2027-06-30');
150	      expect(res.body.sku_id).toBe(skuId);
151	
152	      lotId = res.body.id;
153	    });
154	  });
155	
156	  // -------------------------------------------------------------------------
157	  // 2. GET /inventory/lots -> 200, returns lots
158	  // -------------------------------------------------------------------------
159	  describe('GET /inventory/lots', () => {
160	    it('should return a list of lots', async () => {
161	      logStep('GET', '/inventory/lots');
162	      const res = await request(server)
163	        .get('/inventory/lots')
164	        .set('Authorization', `Bearer ${adminToken}`);
165	      logStep('GET', '/inventory/lots', res.status);
166	
167	      expect(res.status).toBe(200);
168	      expect(Array.isArray(res.body)).toBe(true);
169	      expect(res.body.length).toBeGreaterThanOrEqual(1);
170	
171	      const ourLot = res.body.find((l: any) => l.id === lotId);
172	      expect(ourLot).toBeDefined();
173	    });
174	  });
175	
176	  // -------------------------------------------------------------------------
177	  // 3. GET /inventory/lots?skuId=... -> 200, filtered by SKU
178	  // -------------------------------------------------------------------------
179	  describe('GET /inventory/lots?skuId=...', () => {
180	    it('should return only lots belonging to the specified SKU', async () => {
181	      logStep('GET', `/inventory/lots?skuId=${skuId}`);
182	      const res = await request(server)
183	        .get(`/inventory/lots`)
184	        .query({ skuId })
185	        .set('Authorization', `Bearer ${adminToken}`);
186	      logStep('GET', `/inventory/lots?skuId=${skuId}`, res.status);
187	
188	      expect(res.status).toBe(200);
189	      expect(Array.isArray(res.body)).toBe(true);
190	      expect(res.body.length).toBeGreaterThanOrEqual(1);
191	      for (const lot of res.body) {
192	        expect(lot.sku_id).toBe(skuId);
193	      }
194	    });
195	  });
196	
197	  // -------------------------------------------------------------------------
198	  // 4. PATCH /inventory/lots/:id -> 200, update quantity
199	  // -------------------------------------------------------------------------
200	  describe('PATCH /inventory/lots/:id', () => {
201	    it('should update the lot quantity', async () => {
202	      logStep('PATCH', `/inventory/lots/${lotId}`);
