23	  async createHold(seatId: string, userId: string): Promise<Reservation> {
24	    // Use a transaction with row-level lock to prevent race conditions
25	    return this.dataSource.transaction(async (manager) => {
26	      // Lock the seat row for the duration of this transaction
27	      const seat = await manager
28	        .createQueryBuilder(Seat, 'seat')
29	        .setLock('pessimistic_write')
30	        .where('seat.id = :seatId', { seatId })
31	        .getOne();
32	
33	      if (!seat) throw new NotFoundException(`Seat ${seatId} not found`);
34	      if (seat.status === SeatStatus.MAINTENANCE) {
35	        throw new BadRequestException('Seat is currently under maintenance');
36	      }
37	
38	      // Check no active hold exists (within the same locked transaction)
39	      const activeHold = await manager.findOne(Reservation, {
40	        where: {
41	          seat_id: seatId,
42	          status: ReservationStatus.HOLD,
43	          hold_until: MoreThan(new Date()),
44	        },
45	      });
46	      if (activeHold) {
47	        throw new ConflictException('An active hold already exists for this seat');
48	      }
49	
50	      const holdUntil = new Date(Date.now() + 15 * 60 * 1000);
51	
52	      const reservation = manager.create(Reservation, {
53	        seat_id: seatId,
54	        user_id: userId,
55	        status: ReservationStatus.HOLD,
56	        hold_until: holdUntil,
57	      });
58	
59	      return manager.save(reservation);
60	    });
61	  }
