63	  async confirm(reservationId: string, userId: string): Promise<Reservation> {
64	    const reservation = await this.reservationRepo.findOne({
65	      where: { id: reservationId, user_id: userId },
66	    });
67	    if (!reservation) {
68	      throw new NotFoundException(`Reservation ${reservationId} not found`);
69	    }
70	
71	    if (
72	      reservation.status !== ReservationStatus.HOLD ||
73	      reservation.hold_until <= new Date()
74	    ) {
