1	import {
2	  Injectable,
3	  NotFoundException,
4	  BadRequestException,
5	  ForbiddenException,
6	} from '@nestjs/common';
7	import { InjectRepository } from '@nestjs/typeorm';
8	import { Repository, DataSource } from 'typeorm';
9	import { Paper } from './entities/paper.entity';
10	import { PaperQuestion } from './entities/paper-question.entity';
11	import { Attempt, AttemptStatus } from './entities/attempt.entity';
12	import { AttemptAnswer } from './entities/attempt-answer.entity';
13	import { Question, QuestionStatus, QuestionType } from '../questions/entities/question.entity';
14	import { QuestionOption } from '../questions/entities/question-option.entity';
15	import { GeneratePaperDto } from './dto/generate-paper.dto';
16	import { SubmitAnswerDto } from './dto/submit-attempt.dto';
17	
18	@Injectable()
19	export class AssessmentsService {
20	  constructor(
21	    @InjectRepository(Paper)
22	    private readonly paperRepo: Repository<Paper>,
23	    @InjectRepository(PaperQuestion)
24	    private readonly paperQuestionRepo: Repository<PaperQuestion>,
25	    @InjectRepository(Attempt)
26	    private readonly attemptRepo: Repository<Attempt>,
27	    @InjectRepository(AttemptAnswer)
28	    private readonly answerRepo: Repository<AttemptAnswer>,
29	    @InjectRepository(Question)
30	    private readonly questionRepo: Repository<Question>,
31	    @InjectRepository(QuestionOption)
32	    private readonly optionRepo: Repository<QuestionOption>,
33	    private readonly dataSource: DataSource,
34	  ) {}
35	
36	  /**
37	   * Resolves the effective store scope for a caller.
38	   *
39	   * - store_admin  → their assigned store id (403 if none is assigned)
40	   * - everyone else → null (no scope restriction applied)
41	   *
42	   * This is the single place in the service where we decide whether a
43	   * query needs to be tenant-scoped. Returning null for non-store-admin
44	   * preserves platform_admin, content_reviewer, and auditor behavior
45	   * exactly; returning the assigned id for store_admin is what closes
46	   * the cross-store paper read leak.
47	   */
48	  private resolveStoreScope(user?: any): string | null {
49	    if (user?.role === 'store_admin') {
50	      const storeId = user?.storeId ?? user?.store_id ?? null;
51	      if (!storeId) {
52	        throw new ForbiddenException('Store admin has no assigned store');
53	      }
54	      return storeId;
55	    }
56	    return null;
57	  }
58	
59	  /**
60	   * Ownership guard for per-paper reads. For store_admin callers, the
61	   * paper must live in their own store — otherwise we throw 404 (not
62	   * 403) so the existence of cross-store papers isn't leaked through
63	   * the status code, matching the tenant-isolation hiding policy used
64	   * by the questions module.
65	   */
66	  private enforcePaperOwnership(paper: Paper, user?: any): void {
67	    const scope = this.resolveStoreScope(user);
68	    if (scope && paper.store_id !== scope) {
69	      throw new NotFoundException('Paper not found');
70	    }
71	  }
72	
73	  async generatePaper(
74	    dto: GeneratePaperDto,
75	    userId: string,
76	    storeId?: string,
77	  ): Promise<Paper> {
78	    const { generationRule } = dto;
79	    let questions: Question[];
80	
81	    if (generationRule.type === 'random') {
82	      const count = generationRule.count ?? 10;
83	      const qb = this.questionRepo
84	        .createQueryBuilder('q')
85	        .where('q.status = :status', { status: QuestionStatus.APPROVED });
86	
87	      if (storeId) {
88	        qb.andWhere('(q.store_id = :storeId OR q.store_id IS NULL)', {
89	          storeId,
90	        });
91	      }
92	
93	      questions = await qb
94	        .orderBy('RANDOM()')
95	        .limit(count)
96	        .getMany();
97	    } else {
98	      // rule-based
99	      const qb = this.questionRepo
100	        .createQueryBuilder('q')
101	        .where('q.status = :status', { status: QuestionStatus.APPROVED });
102	
103	      if (storeId) {
104	        qb.andWhere('(q.store_id = :storeId OR q.store_id IS NULL)', {
105	          storeId,
106	        });
107	      }
108	
109	      const filters = generationRule.filters ?? {};
110	      if (filters.type) {
111	        qb.andWhere('q.type = :type', { type: filters.type });
112	      }
113	
114	      const count = generationRule.count;
115	      if (count) {
116	        qb.limit(count);
117	      }
118	
119	      questions = await qb.getMany();
120	    }
121	
122	    const paper = this.paperRepo.create({
123	      name: dto.name,
124	      generation_rule: generationRule as any,
125	      created_by: userId,
126	      store_id: storeId ?? null,
127	    });
128	
129	    const savedPaper = await this.paperRepo.save(paper);
130	
131	    const paperQuestions = questions.map((q, index) =>
132	      this.paperQuestionRepo.create({
133	        paper_id: savedPaper.id,
134	        question_id: q.id,
135	        position: index + 1,
136	      }),
137	    );
138	
139	    await this.paperQuestionRepo.save(paperQuestions);
140	    savedPaper.paper_questions = paperQuestions;
141	
142	    return savedPaper;
143	  }
144	
145	  async startAttempt(paperId: string, userId: string): Promise<Attempt> {
146	    const paper = await this.paperRepo.findOne({ where: { id: paperId } });
147	    if (!paper) {
148	      throw new NotFoundException('Paper not found');
149	    }
150	
151	    const attempt = this.attemptRepo.create({
152	      paper_id: paperId,
153	      user_id: userId,
154	      status: AttemptStatus.IN_PROGRESS,
155	      started_at: new Date(),
156	    });
157	
158	    return this.attemptRepo.save(attempt);
159	  }
160	
161	  async submitAttempt(
162	    attemptId: string,
163	    answers: SubmitAnswerDto[],
164	    userId: string,
165	  ): Promise<Attempt> {
166	    const attempt = await this.attemptRepo.findOne({
167	      where: { id: attemptId },
168	    });
169	
170	    if (!attempt) {
171	      throw new NotFoundException('Attempt not found');
172	    }
173	
174	    if (attempt.user_id !== userId) {
175	      throw new BadRequestException('Attempt does not belong to this user');
176	    }
177	
178	    if (attempt.status !== AttemptStatus.IN_PROGRESS) {
179	      throw new BadRequestException('Attempt is not in progress');
180	    }
181	
182	    const now = new Date();
183	    let correctCount = 0;
184	    let totalObjective = 0;
185	    const attemptAnswers: AttemptAnswer[] = [];
186	
187	    for (const ans of answers) {
188	      const question = await this.questionRepo.findOne({
189	        where: { id: ans.questionId },
190	      });
191	
192	      if (!question) {
193	        throw new NotFoundException(`Question ${ans.questionId} not found`);
194	      }
195	
196	      let isCorrect: boolean | null = null;
197	
198	      if (question.type === QuestionType.OBJECTIVE) {
199	        totalObjective++;
200	
201	        if (ans.selectedOptionId) {
202	          const option = await this.optionRepo.findOne({
203	            where: { id: ans.selectedOptionId },
204	          });
205	
206	          if (option) {
207	            isCorrect = option.is_correct;
208	            if (isCorrect) {
209	              correctCount++;
210	            }
211	          } else {
212	            isCorrect = false;
213	          }
214	        } else {
215	          isCorrect = false;
216	        }
217	      }
218	      // subjective: is_correct remains null
219	
220	      const attemptAnswer = this.answerRepo.create({
221	        attempt_id: attemptId,
222	        question_id: ans.questionId,
223	        selected_option_id: ans.selectedOptionId ?? null,
224	        text_answer: ans.textAnswer ?? null,
225	        is_correct: isCorrect,
226	      });
227	
228	      attemptAnswers.push(attemptAnswer);
229	    }
230	
231	    await this.answerRepo.save(attemptAnswers);
232	
233	    const score =
234	      totalObjective > 0
235	        ? Math.round((correctCount / totalObjective) * 10000) / 100
236	        : null;
237	
238	    attempt.status = AttemptStatus.GRADED;
239	    attempt.graded_at = now;
240	    attempt.submitted_at = now;
241	    attempt.score = score;
242	    attempt.answers = attemptAnswers;
243	
244	    return this.attemptRepo.save(attempt);
245	  }
246	
247	  async redoAttempt(attemptId: string, userId: string): Promise<Attempt> {
248	    const original = await this.attemptRepo.findOne({
249	      where: { id: attemptId },
250	    });
251	
252	    if (!original) {
253	      throw new NotFoundException('Attempt not found');
254	    }
255	
256	    if (original.user_id !== userId) {
257	      throw new BadRequestException('Attempt does not belong to this user');
258	    }
259	
260	    const newAttempt = this.attemptRepo.create({
261	      paper_id: original.paper_id,
262	      user_id: userId,
263	      parent_attempt_id: attemptId,
264	      status: AttemptStatus.IN_PROGRESS,
265	      started_at: new Date(),
266	    });
267	
268	    return this.attemptRepo.save(newAttempt);
269	  }
270	
271	  async getHistory(userId: string): Promise<Attempt[]> {
272	    return this.attemptRepo.find({
273	      where: { user_id: userId },
274	      order: { started_at: 'DESC' },
275	      relations: ['paper'],
276	    });
277	  }
278	
279	  async getPapers(user?: any, storeId?: string): Promise<Paper[]> {
280	    // store_admin: always filter by the JWT's assigned store — the
281	    // caller-supplied `storeId` query param is ignored on purpose.
282	    // Trusting it here would re-introduce the cross-store read leak
283	    // this method is being hardened against.
284	    //
285	    // Everyone else (platform_admin / content_reviewer / auditor):
286	    // keep the existing behavior — optional `storeId` query param
287	    // narrows the listing; omitting it returns all papers.
288	    const scopedStoreId = this.resolveStoreScope(user);
289	    const where: any = {};
290	    if (scopedStoreId) {
291	      where.store_id = scopedStoreId;
292	    } else if (storeId) {
293	      where.store_id = storeId;
294	    }
295	    return this.paperRepo.find({ where, relations: ['paper_questions'] });
296	  }
297	
298	  async getPaper(id: string, user?: any): Promise<Paper> {
299	    const paper = await this.paperRepo.findOne({
300	      where: { id },
301	      relations: ['paper_questions', 'paper_questions.question', 'paper_questions.question.options'],
302	    });
303	
304	    if (!paper) {
305	      throw new NotFoundException('Paper not found');
306	    }
307	
308	    // Tenant-isolation check — for store_admin, a paper in another
309	    // store is indistinguishable from a missing paper (404, not 403).
310	    this.enforcePaperOwnership(paper, user);
311	
312	    return paper;
313	  }
314	}
