310	  calculateDiscount(promotion: Promotion, orderTotalCents: number): number {
311	    if (
312	      promotion.min_order_cents !== null &&
313	      orderTotalCents < promotion.min_order_cents
314	    ) {
315	      return 0;
316	    }
317	
318	    if (promotion.discount_type === DiscountType.FIXED_CENTS) {
319	      return promotion.discount_value;
320	    }
321	
322	    // percentage
323	    return Math.floor((orderTotalCents * promotion.discount_value) / 100);
324	  }
325	
326	  async resolvePromotions(
327	    orderTotalCents: number,
328	    userId: string,
329	    storeId: string,
330	    couponCode?: string,
331	  ): Promise<ResolvedPromotion> {
332	    const now = new Date();
333	
334	    // 1. Find all active automatic promotions for the store within time window, not capped
335	    const qb = this.promotionRepo
336	      .createQueryBuilder('p')
337	      .where('p.store_id = :storeId', { storeId })
338	      .andWhere('p.active = true')
339	      .andWhere('(p.starts_at IS NULL OR p.starts_at <= :now)', { now })
340	      .andWhere('(p.ends_at IS NULL OR p.ends_at >= :now)', { now })
341	      .andWhere(
342	        '(p.redemption_cap IS NULL OR p.redemption_count < p.redemption_cap)',
343	      );
344	
345	    const autoPromotions = await qb.getMany();
346	
347	    // Filter out first_order promotions if user has prior orders
348	    const filteredPromotions: Promotion[] = [];
349	    for (const promo of autoPromotions) {
350	      if (promo.type === PromotionType.FIRST_ORDER) {
351	        // Check if user has any prior redeemed claims (proxy for orders)
352	        const priorClaim = await this.claimRepo.findOne({
353	          where: { user_id: userId, redeemed_at: MoreThanOrEqual(new Date(0)) },
354	        });
355	        if (priorClaim) {
356	          continue; // skip first_order promo if user has prior orders
357	        }
358	      }
359	      filteredPromotions.push(promo);
360	    }
361	
362	    // 3. Sort by priority DESC
363	    filteredPromotions.sort((a, b) => {
364	      if (b.priority !== a.priority) return b.priority - a.priority;
365	      // 4. Tie-break: highest effective discount
366	      const discA = this.calculateDiscount(a, orderTotalCents);
367	      const discB = this.calculateDiscount(b, orderTotalCents);
368	      if (discB !== discA) return discB - discA;
369	      // 5. Still tied: lower UUID wins
370	      return a.id < b.id ? -1 : 1;
371	    });
372	
373	    const bestAutoPromo = filteredPromotions.length > 0 ? filteredPromotions[0] : null;
374	
375	    // 2. If couponCode provided, validate coupon and get linked promotion
376	    let selectedCoupon: Coupon | null = null;
377	    let couponPromotion: Promotion | null = null;
378	
379	    if (couponCode) {
380	      const coupon = await this.couponRepo.findOne({
381	        where: { code: couponCode },
382	        relations: ['promotion'],
383	      });
384	
385	      if (
386	        coupon &&
387	        coupon.status === CouponStatus.ACTIVE &&
388	        (!coupon.starts_at || coupon.starts_at <= now) &&
389	        (!coupon.ends_at || coupon.ends_at >= now)
390	      ) {
391	        selectedCoupon = coupon;
392	        couponPromotion = coupon.promotion;
393	      }
394	    }
395	
396	    // 8. Max one coupon + one automatic promotion per order
397	    let totalDiscount = 0;
398	    let selectedPromotion: Promotion | null = null;
399	
400	    if (bestAutoPromo) {
401	      const autoDiscount = this.calculateDiscount(bestAutoPromo, orderTotalCents);
402	      if (autoDiscount > 0) {
403	        totalDiscount += autoDiscount;
404	        selectedPromotion = bestAutoPromo;
405	      }
406	    }
407	
408	    if (couponPromotion) {
409	      const couponDiscount = this.calculateDiscount(couponPromotion, orderTotalCents);
410	      if (couponDiscount > 0) {
411	        totalDiscount += couponDiscount;
412	        // If no auto promo was selected, the coupon promotion becomes the selected one
413	        if (!selectedPromotion) {
414	          selectedPromotion = couponPromotion;
415	        }
416	      }
417	    }
418	
419	    return {
420	      selectedPromotion,
421	      selectedCoupon,
422	      totalDiscount,
423	    };
424	  }
