427	  async handleExpiredCoupons(): Promise<void> {
428	    const now = new Date();
429	    const result = await this.couponRepo
430	      .createQueryBuilder()
431	      .update(Coupon)
432	      .set({ status: CouponStatus.EXPIRED })
433	      .where('status = :status', { status: CouponStatus.ACTIVE })
434	      .andWhere('ends_at IS NOT NULL')
435	      .andWhere('ends_at < :now', { now })
436	      .execute();
437	
438	    if (result.affected && result.affected > 0) {
439	      this.logger.log(`Expired ${result.affected} coupons`);
440	    }
441	  }
