50	  async createOrder(
51	    dto: CreateOrderDto,
52	    user: any,
53	  ): Promise<{ order: Order; alreadyExisted: boolean }> {
54	    // 1. Idempotency check
55	    const existingKey = await this.idempotencyRepo.findOne({
56	      where: { key: dto.idempotencyKey },
57	    });
58	    if (existingKey) {
59	      const existingOrder = await this.orderRepo.findOne({
60	        where: { idempotency_key: dto.idempotencyKey },
