63	      return { order: existingOrder, alreadyExisted: true };
64	    }
65	
66	    // 2. Look up SKU prices, compute subtotal
67	    const skuIds = dto.items.map((i) => i.skuId);
68	    const skus = await this.skuRepo
69	      .createQueryBuilder('sku')
70	      .whereInIds(skuIds)
71	      .getMany();
72	
73	    const skuMap = new Map<string, Sku>();
74	    for (const sku of skus) {
75	      skuMap.set(sku.id, sku);
76	    }
77	
78	    for (const item of dto.items) {
79	      if (!skuMap.has(item.skuId)) {
80	        throw new NotFoundException(`SKU ${item.skuId} not found`);
81	      }
82	    }
83	
84	    let subtotalCents = 0;
85	    const itemEntries: { skuId: string; quantity: number; unitPriceCents: number }[] = [];
86	    for (const item of dto.items) {
87	      const sku = skuMap.get(item.skuId);
88	      const unitPrice = sku.member_price_cents ?? sku.price_cents;
89	      subtotalCents += unitPrice * item.quantity;
90	      itemEntries.push({
91	        skuId: item.skuId,
92	        quantity: item.quantity,
93	        unitPriceCents: unitPrice,
94	      });
95	    }
96	
97	    // 3. Resolve promotions/coupons (max one auto + one coupon)
98	    const storeId = this.enforceStoreScope(user) || this.getUserStoreId(user);
99	    let discountCents = 0;
100	    let promotionId: string | null = null;
101	    let couponId: string | null = null;
102	
103	    if (storeId) {
104	      const resolved = await this.promotionsService.resolvePromotions(
105	        subtotalCents,
