132	        internal_notes: encryptedNotes,
133	        status: OrderStatus.PENDING,
134	      });
135	      const savedOrder = await manager.save(order);
136	
137	      const items = itemEntries.map((entry) =>
138	        manager.create(OrderItem, {
139	          order_id: savedOrder.id,
140	          sku_id: entry.skuId,
141	          quantity: entry.quantity,
142	          unit_price_cents: entry.unitPriceCents,
143	        }),
144	      );
145	      await manager.save(items);
146	
147	      // 5. Store idempotency record
148	      const idempotencyRecord = manager.create(IdempotencyKey, {
149	        key: dto.idempotencyKey,
150	        operation_type: 'create_order',
151	        response_body: { orderId: savedOrder.id },
