121	      if (!skuMap.has(item.skuId)) {
122	        throw new NotFoundException(`SKU ${item.skuId} not found`);
123	      }
124	    }
125	
126	    let subtotalCents = 0;
127	    const itemEntries: { skuId: string; quantity: number; unitPriceCents: number }[] = [];
